def gcd(a, b):
    if b == 0:
        return a
    return gcd(b, a % b)


def lcm(a, b):
    return a * b // gcd(a, b)


def lcm_r(a, b):
    return a // gcd(a, b) * b


def solve(b):
    ans = 0
    for i in range(1, b + 1):
        ans += lcm_r(b, i)
    return ans


if __name__ == "__main__":
    b = int(input())
    print(solve(b))
